import{_ as a,a as d,b as r,c as e}from"./chunks/下载好后的视频.pSSnkGgz.js";import{_ as l,o,c as i,a2 as h}from"./chunks/framework.DnrXFDHb.js";const g=JSON.parse('{"title":"마그넷 링크 전송 안내","description":"","frontmatter":{},"headers":[],"relativePath":"ko-KR/Other/magnet-transfer.md","filePath":"ko-KR/Other/magnet-transfer.md","lastUpdated":1781962217000}'),n={name:"ko-KR/Other/magnet-transfer.md"};function s(p,t,c,b,m,_){return o(),i("div",null,[...t[0]||(t[0]=[h('<h1 id="마그넷-링크-전송-안내" tabindex="-1">마그넷 링크 전송 안내 <a class="header-anchor" href="#마그넷-링크-전송-안내" aria-label="Permalink to &quot;마그넷 링크 전송 안내&quot;">​</a></h1><p>마그넷 링크 기능은 마그넷 링크 안의 파일을 내려받은 뒤, 지정한 클라우드 업로드 채널로 자동 업로드합니다.</p><p>애니메이션, 동영상, 압축 파일 등을 옮길 때 유용합니다. 링크를 붙여 넣으면 백그라운드에서 다운로드 작업이 만들어지고, 완료 후 업로드 목록에 최종 링크가 표시됩니다.</p><p><img src="'+a+'" alt="마그넷 링크" loading="lazy"></p><h2 id="사용-위치" tabindex="-1">사용 위치 <a class="header-anchor" href="#사용-위치" aria-label="Permalink to &quot;사용 위치&quot;">​</a></h2><p>홈 화면의 업로드 영역에서 사용할 수 있습니다.</p><p>마그넷 링크를 입력창에 붙여 넣고, 모드를 <code>전송</code>으로 선택한 뒤 업로드를 누릅니다.</p><p><img src="'+d+'" alt="마그넷 전송 업로드" loading="lazy"></p><h2 id="사용-전-준비" tabindex="-1">사용 전 준비 <a class="header-anchor" href="#사용-전-준비" aria-label="Permalink to &quot;사용 전 준비&quot;">​</a></h2><p>관리 화면에서 마그넷 전송 설정을 먼저 완료해야 합니다.</p><p>보통 다음 항목이 필요합니다.</p><table tabindex="0"><thead><tr><th>준비 항목</th><th>용도</th></tr></thead><tbody><tr><td>GitHub 계정</td><td>다운로드 작업 실행에 사용</td></tr><tr><td>업로드 채널</td><td>Google Drive, OneDrive 같은 최종 저장 위치</td></tr><tr><td>저장 디렉터리</td><td>전송 완료 파일이 저장될 경로</td></tr><tr><td>작업 제한 시간</td><td>오래 걸리는 작업의 타임아웃</td></tr></tbody></table><h2 id="전송-방법" tabindex="-1">전송 방법 <a class="header-anchor" href="#전송-방법" aria-label="Permalink to &quot;전송 방법&quot;">​</a></h2><ol><li>홈 화면 업로드 입력창에 마그넷 링크를 붙여 넣습니다.</li><li>모드가 <code>전송</code>인지 확인합니다.</li><li>업로드를 누릅니다.</li><li>시스템이 마그넷 작업을 만들 때까지 기다립니다.</li><li>작업이 시작되면 오른쪽 아래의 <code>마그넷 작업</code> 창에서 진행률을 확인합니다.</li></ol><p>다운로드와 업로드에는 시간이 걸릴 수 있습니다. 속도는 마그넷 소스 상태, GitHub 실행 환경, 선택한 저장 채널에 따라 달라집니다.</p><p><img src="'+r+'" alt="다운로드 중" loading="lazy"></p><h2 id="완료-후" tabindex="-1">완료 후 <a class="header-anchor" href="#완료-후" aria-label="Permalink to &quot;완료 후&quot;">​</a></h2><p>작업이 끝나면 업로드 목록에 파일명과 링크가 표시됩니다.</p><p>동영상은 동영상 미리보기로, 이미지는 이미지 미리보기로, 그 외 파일은 일반 파일 아이콘으로 표시됩니다.</p><p><img src="'+e+'" alt="완료된 동영상" loading="lazy"></p><p>다음 형식의 링크를 바로 복사할 수 있습니다.</p><table tabindex="0"><thead><tr><th>링크 형식</th><th>사용처</th></tr></thead><tbody><tr><td>원본 링크</td><td>파일을 직접 열 때</td></tr><tr><td>Markdown</td><td>Markdown 글이나 설명에 붙여 넣을 때</td></tr><tr><td>HTML</td><td>웹 페이지 코드에 넣을 때</td></tr><tr><td>BBCode</td><td>BBCode를 지원하는 게시판에서 사용할 때</td></tr></tbody></table><h2 id="작업-상태" tabindex="-1">작업 상태 <a class="header-anchor" href="#작업-상태" aria-label="Permalink to &quot;작업 상태&quot;">​</a></h2><table tabindex="0"><thead><tr><th>상태</th><th>의미</th></tr></thead><tbody><tr><td>대기 중</td><td>작업이 생성되어 실행을 기다리는 중</td></tr><tr><td>다운로드 중</td><td>마그넷 리소스를 내려받는 중</td></tr><tr><td>업로드 중</td><td>내려받은 파일을 클라우드 채널로 업로드하는 중</td></tr><tr><td>완료</td><td>업로드가 끝나 링크를 복사할 수 있음</td></tr><tr><td>실패</td><td>안내 메시지를 확인한 뒤 다시 시도해야 함</td></tr></tbody></table><h2 id="문제-해결" tabindex="-1">문제 해결 <a class="header-anchor" href="#문제-해결" aria-label="Permalink to &quot;문제 해결&quot;">​</a></h2><ul><li>링크를 붙여 넣었는데 시작하지 않으면 마그넷 전송이 켜져 있고, GitHub 계정과 업로드 채널이 선택되어 있는지 확인합니다.</li><li>다운로드가 계속 느리면 마그넷 자체에 유효한 피어가 부족할 수 있습니다.</li><li>완료 후 미리보기가 보이지 않으면 먼저 파일 링크가 직접 열리는지 확인합니다.</li><li>작업이 실패하면 마그넷 링크, 저장 채널, 업로드 디렉터리 설정을 다시 확인합니다.</li></ul>',26)])])}const k=l(n,[["render",s]]);export{g as __pageData,k as default};
